    // 3. Identify Valid Elements
    const result = [];
    for (let i = 0; i < N; i++) {
        const current = nums[i];

        // Condition 1: Strictly greater than all elements to the left
        const strictlyGreaterThanLeft = current > LMax[i];

        // Condition 2: Strictly greater than all elements to the right
        const strictlyGreaterThanRight = current > RMax[i];

        // Valid if Condition 1 OR Condition 2 is met
        if (strictlyGreaterThanLeft || strictlyGreaterThanRight) {
            result.push(current);
        }
    }

    return result;
}

